worked_example.sympy_code:
from sympy import *
wynik = log(9, sqrt(3))
wynik_num = simplify(wynik)
print(f"Obliczony wynik: {wynik_num}")
# Porównaj z opcjami
opcje = {'A': 2, 'B': 3, 'C': 4, 'D': 9}
for litera, val in opcje.items():
    if abs(float(wynik_num) - val) < 0.001:
        print(f"ODPOWIEDZ: {litera}")
        break
